const installFile = "/data/smart_jkbms_premium.json";

let installId = "";
let payload = {};

try {
    if (!fs.existsSync(installDir)) {
        fs.mkdirSync(installDir, { recursive: true });
    }

    if (fs.existsSync(installFile)) {
        const raw = fs.readFileSync(installFile, "utf8");
        payload = JSON.parse(raw || "{}");
    }

    installId = normStr(payload.install_id);

    if (!installId) {
        installId = generateInstallId();
        payload.install_id = installId;
        fs.writeFileSync(installFile, JSON.stringify(payload, null, 2), "utf8");
    }

    global.set("premium.install_id", installId);
    global.set("premium.storage_file", installFile);

    node.status({ fill: "green", shape: "dot", text: "install_id ready" });

    msg.payload = {
        install_id: installId,
        file: installFile
    };

    return msg;

} catch (err) {
    node.error("PREMIUM STORAGE INIT error: " + err.message, msg);
    node.status({ fill: "red", shape: "ring", text: "storage init error" });
    return null;
}

const crypto = global.get("crypto");

function normStr(v) {
    return (v ?? "").toString().trim();
}

const LICENSE_SECRET = "SJK_2026_9f7c2e51b4d84f38a1e9c7b6d5e4f301_ULTRA_LONG_SECRET";

function signPayload(payload) {
    return crypto
        .createHmac("sha256", LICENSE_SECRET)
        .update(payload, "utf8")
        .digest("hex");
}

const premiumKey = normStr(global.get("premium.key"));
const installId = normStr(global.get("premium.install_id"));

let premiumActive = false;
let premiumStatus = "missing_key";
let premiumTier = null;

if (!crypto) {
    premiumStatus = "crypto_missing";
} else if (!installId) {
    premiumStatus = "missing_install_id";
} else if (!premiumKey) {
    premiumStatus = "missing_key";
} else {
    const parts = premiumKey.split("|");

    if (parts.length !== 4) {
        premiumStatus = "invalid_format";
    } else {
        const prefix = normStr(parts[0]);
        const tier = normStr(parts[1]);
        const licenseInstallId = normStr(parts[2]);
        const signature = normStr(parts[3]);

        if (prefix !== "SJK") {
            premiumStatus = "invalid_prefix";
        } else if (tier !== "premium") {
            premiumStatus = "invalid_tier";
        } else if (licenseInstallId !== installId) {
            premiumStatus = "install_id_mismatch";
        } else {
            const payload = `${prefix}|${tier}|${licenseInstallId}`;
            const expected = signPayload(payload);

            if (signature !== expected) {
                premiumStatus = "invalid_signature";
            } else {
                premiumActive = true;
                premiumStatus = "valid";
                premiumTier = "premium";
                global.set("premium.last_valid", Date.now());
            }
        }
    }
}

global.set("premium.active", premiumActive);
global.set("premium.status", premiumStatus);
global.set("premium.tier", premiumTier);

