    newRCVTime_raw = Math.round(newValue * 10);
    node.warn(`Modification RCVTime: ${currentRCVTime_raw} -> ${newRCVTime_raw} (${newValue}h)`);
} else if (fieldToUpdate === "RFVTime") {
    const newValue = flow.get("new_RFVTime");
    newRFVTime_raw = Math.round(newValue * 10);
    node.warn(`Modification RFVTime: ${currentRFVTime_raw} -> ${newRFVTime_raw} (${newValue}h)`);
} else {
    node.error("Champ à modifier non défini");
    return null;
}

// Validation
if (newRCVTime_raw < 0 || newRCVTime_raw > 100 || newRFVTime_raw < 0 || newRFVTime_raw > 100) {
    node.error("Valeurs hors limites (0-10h)");
    return null;
}

// Passer les nouvelles valeurs au nœud suivant
msg.payload = {
    RCVTime: newRCVTime_raw,
    RFVTime: newRFVTime_raw
};

return msg;

// Génération de la trame d'écriture Modbus avec les nouvelles valeurs
const slaveId = global.get("slaveAddress-Trame1") || 0x01;
const rcvRaw = msg.payload.RCVTime;
const rfvRaw = msg.payload.RFVTime;

// Calculer CRC16 Modbus
function crc16(buffer) {
    let crc = 0xFFFF;
    for (let i = 0; i < buffer.length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            if (crc & 0x0001) {
                crc = (crc >> 1) ^ 0xA001;
            } else {
                crc = crc >> 1;
            }
        }
    }
    return crc;
}

// Construction de la trame sans CRC
const dataBuffer = Buffer.from([
    slaveId,
    0x06,           // Function code (Write Single Register)
    0x15,           // Register address high byte
    0x04,           // Register address low byte
    rcvRaw & 0xFF,  // Value high byte (RCVTime)
    rfvRaw & 0xFF   // Value low byte (RFVTime)
]);

// Calcul du CRC
const crc = crc16(dataBuffer);

// Buffer final avec CRC
const finalBuffer = Buffer.allocUnsafe(dataBuffer.length + 2);
dataBuffer.copy(finalBuffer);
finalBuffer.writeUInt16LE(crc, dataBuffer.length);

node.warn(`Écriture registre 0x1504 - RCVTime: ${rcvRaw} | RFVTime: ${rfvRaw}`);

msg.topic = "write_voltage_times";
msg.payload = finalBuffer;
return msg;

// Récupération de l'adresse esclave depuis le contexte global
const slaveId = global.get("slaveAddress-Trame1") || 0x01; // Valeur par défaut si non définie
const functionCode = 0x03; // Function Code 3 : Read Holding Registers
const registerHigh = 0x15; // Adresse haute de 0x1504
const registerLow = 0x04;  // Adresse basse de 0x1504
const quantityHigh = 0x00; // Nombre de registres haute (0x0001 = 1 registre)
const quantityLow = 0x01;  // Nombre de registres basse

// Calculer CRC16 Modbus
function crc16(buffer) {
    let crc = 0xFFFF;
    for (let i = 0; i < buffer.length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            if (crc & 0x0001) {
                crc = (crc >> 1) ^ 0xA001;
            } else {
                crc = crc >> 1;
            }
        }
    }
    return crc;
}

// Construction du buffer sans CRC
const dataBuffer = Buffer.from([
    slaveId,
    functionCode,
    registerHigh,
    registerLow,
    quantityHigh,
    quantityLow
]);

// Calcul du CRC
const crc = crc16(dataBuffer);

// Buffer final avec CRC
const finalBuffer = Buffer.allocUnsafe(dataBuffer.length + 2);
dataBuffer.copy(finalBuffer);
finalBuffer.writeUInt16LE(crc, dataBuffer.length);

msg.topic = "Trame-1-statiques";
msg.payload = finalBuffer;
return msg;

// ========== AGGREGATION GLOBALE DES ALARMES BMS ==========
// Ce nœud agrège les alarmes de tous les BMS et crée un binary_sensor global

// Récupération des données d'alarme du BMS courant
const alarmData = msg.alarms;

if (!alarmData || !alarmData.bms_id) {
    node.error("Données d'alarme invalides ou BMS ID manquant");
    return null;
}

const bmsId = alarmData.bms_id;

// ------------------------------------------------------------------
// 1. Configuration
const TOTAL_BMS = global.get("nb_jkbms") || 4; // Récupération depuis la variable globale
const discoveryPrefix = "homeassistant";
const globalDeviceID = "BMS_GLOBAL_device";
const globalDeviceName = "BMS Global";

// ------------------------------------------------------------------
// 2. Stockage de l'état des alarmes dans le contexte flow
// Clé unique pour stocker l'état de chaque BMS
const alarmStateKey = `bms_alarm_state_${bmsId}`;
const globalDiscoveryKey = "discoverySent_GLOBAL_ALARM";

// Stocker l'état actuel de ce BMS
flow.set(alarmStateKey, {
    has_alarm: alarmData.has_alarms,
    alarm_count: alarmData.alarm_count,
    timestamp: new Date().toISOString(),
    active_alarms: alarmData.active_alarms
});

// ------------------------------------------------------------------
// 3. Calcul de l'état global en parcourant tous les BMS
let globalHasAlarm = false;
let totalAlarmCount = 0;
let alarmedBmsList = [];

for (let i = 1; i <= TOTAL_BMS; i++) {
    const stateKey = `bms_alarm_state_${i}`;
    const bmsState = flow.get(stateKey);

    if (bmsState && bmsState.has_alarm) {
        globalHasAlarm = true;
        totalAlarmCount += bmsState.alarm_count;
        alarmedBmsList.push(`BMS ${i}`);
    }
}

// ------------------------------------------------------------------
// 4. Fonction de génération du message discovery (une seule fois)
function buildGlobalDiscoveryMessage() {
    const binarySensorConfig = {
        name: "BMS Global Alarm",
        unique_id: `${globalDeviceID}_alarm_active`,
        state_topic: "BMS_GLOBAL/alarm/state",
        payload_on: "ON",
        payload_off: "OFF",
        device_class: "problem",
        icon: "mdi:battery-alert",
        device: {
            identifiers: [globalDeviceID],
            name: globalDeviceName,
            manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
            model: "JK-BMS Aggregator",
            sw_version: "3.5"
        }
    };

    return {
        topic: `${discoveryPrefix}/binary_sensor/${globalDeviceID}/alarm_active/config`,
        payload: binarySensorConfig,
        retain: true
    };
}

// ------------------------------------------------------------------
// 5. Fonction de génération du message state
function buildGlobalStateMessage() {
    return {
        topic: "BMS_GLOBAL/alarm/state",
        payload: globalHasAlarm ? "ON" : "OFF",
        retain: true,
        qos: 1
    };
}

// ------------------------------------------------------------------
// 6. Construction et envoi des messages
const discoveryAlreadySent = flow.get(globalDiscoveryKey) || false;
const messages = [];

// Envoyer le discovery une seule fois
if (!discoveryAlreadySent) {
    messages.push(buildGlobalDiscoveryMessage());
    flow.set(globalDiscoveryKey, true);
    //node.log(`✓ Discovery envoyé pour BMS Global Alarm (${TOTAL_BMS} BMS surveillés)`);
}

// Toujours envoyer le state
messages.push(buildGlobalStateMessage());

// Log de l'état global
if (globalHasAlarm) {
    node.warn(`🚨 ALARME GLOBALE: ${totalAlarmCount} alarme(s) sur ${alarmedBmsList.join(", ")}`);
} else {
    //node.log(`✓ BMS Global: Aucune alarme active (${TOTAL_BMS} BMS OK)`);
}

// Retourner tous les messages (discovery + state)
return [messages];

