// ========== TRAITEMENT RÉPONSE ALARMES JK-BMS ==========

const ALARM_BITS = {
    0: "Balancing resistance too high",
    1: "MOS over-temperature protection",
    2: "Number of cells does not match parameter",
    3: "Abnormal current sensor",
    4: "Cell over-voltage protection",
    5: "Battery over-voltage protection",
    6: "Overcurrent charge protection",
    7: "Charge short-circuit protection",
    8: "Over-temperature charge protection",
    9: "Low temperature charge protection",
    10: "Internal communication anomaly",
    11: "Cell under-voltage protection",
    12: "Battery under-voltage protection",
    13: "Overcurrent discharge protection",
    14: "Discharge short-circuit protection",
    15: "Over-temperature discharge protection",
    16: "Charge MOS anomaly",
    17: "Discharge MOS anomaly",
    18: "GPS disconnected",
    19: "Please modify the authorization password in time",
    20: "Discharge activation failure",
    21: "Battery over-temperature alarm",
    22: "Temperature sensor anomaly",
    23: "Parallel module anomaly"
};

if (msg.topic !== "Trame-Alarmes-BMS") {
    return null;
}

if (!Buffer.isBuffer(msg.payload) || msg.payload.length < 7) {
    node.error("Réponse alarmes invalide");
    return null;
}

// IMPORTANT : l'adresse réelle du BMS est dans la réponse Modbus
const slaveId = Number(msg.payload[0]);

if (!Number.isFinite(slaveId) || slaveId <= 0) {
    node.error("Adresse BMS invalide dans la réponse alarme");
    return null;
}

const byteCount = msg.payload[2];

if (byteCount !== 4) {
    node.error(`Nombre d'octets alarmes incorrect: ${byteCount}, attendu: 4`);
    return null;
}

const alarmValue = msg.payload.readUInt32BE(3);

const activeAlarms = [];
const alarmDetails = {};
const alarmBits = [];

for (let bit = 0; bit <= 23; bit++) {
    if (alarmValue & (1 << bit)) {
        const description = ALARM_BITS[bit] || `Unknown alarm bit ${bit}`;
        activeAlarms.push({ bit, description });
        alarmDetails[`BIT${bit}`] = description;
        alarmBits.push(bit);
    }
}

alarmDetails.status = activeAlarms.length === 0
    ? "No BMS alarms"
    : "🚨 BMS Alarm Alert";

msg.alarms = {
    bms_id: slaveId,
    timestamp: new Date().toISOString(),
    slave_id: slaveId,
    raw_value: alarmValue,
    raw_hex: "0x" + alarmValue.toString(16).toUpperCase().padStart(8, "0"),
    raw_binary: alarmValue.toString(2).padStart(24, "0"),
    alarm_count: activeAlarms.length,
    has_alarms: activeAlarms.length > 0,
    active_bits: alarmBits,
    active_alarms: activeAlarms,
    alarm_details: alarmDetails
};

msg.payload = {
    bms_id: slaveId,
    status: activeAlarms.length > 0 ? "ALARM" : "OK",
    count: activeAlarms.length,
    alarms: activeAlarms.map(a => a.description),
    bits: alarmBits,
    timestamp: new Date().toISOString()
};

msg.bmsId = slaveId;
msg.bms_id = slaveId;
msg.bms_numero = slaveId;
msg.topic = `jkbms/alarms/bms${slaveId}`;

return msg;

// Réinitialise toutes les clés de discovery au démarrage
const keys = flow.keys();
keys.forEach(k => {
    if (k.startsWith("discoverySent_BMS_")) {
        flow.set(k, undefined);
