return msg;

// Réinitialise toutes les clés de discovery au démarrage
const keys = flow.keys();
keys.forEach(k => {
    if (k.startsWith("discoverySent_ALARMS_BMS_")) {
        flow.set(k, undefined);
    }
});
return msg;

flow.set("discoverySent_GLOBAL_ALARM", null);
//node.warn("✓ Verrou discovery réinitialisé");
return msg;

// Récupérer ou initialiser le tableau
let tableau_0x1114 = global.get('0x1114') || [];

// Extraire les données
let uint16_value = msg.payload["0x1114"];  // ex: 0x0210 (valeur UINT16)
let bms_number = global.get('slaveAddress-Trame2');  // 0 à 15
//let bms_number = msg.payload["Device_address_N"] ;  // 0 à 15

// Vérifier si ce bms_number existe déjà
