if (index !== -1) {
    // Mettre à jour la ligne existante
    tableau_0x1114[index] = [uint16_value, bms_number];
} else {
    // Ajouter une nouvelle ligne
    tableau_0x1114.push([uint16_value, bms_number]);
}

// Sauvegarder dans le contexte global
global.set('0x1114', tableau_0x1114);

// Afficher les détails pour debug
msg.payload = {
    bms: bms_number,
    value: uint16_value,
    value_hex: "0x" + uint16_value.toString(16).toUpperCase().padStart(4, '0'),
    value_binary: "0b" + uint16_value.toString(2).padStart(16, '0'),
    bit9: (uint16_value & 0x0200) ? 1 : 0  // État du bit 9
};

return msg;

let currentAddress = global.get("slaveAddress-Trame2") || 1; // Valeur par défaut : 1
let Number_of_BMS = global.get("nb_jkbms") || 1; // Valeur par défaut : 1

// Incrémenter l'adresse, revenir à 1 après 8
currentAddress = currentAddress >= Number_of_BMS ? 1 : currentAddress + 1;

global.set("slaveAddress-Trame2", currentAddress);

//node.warn(`Prochaine adresse esclave Trame2 : ${currentAddress}`);
msg.payload = currentAddress;
return msg; // Continuer vers le prochain nœud

var BMS = msg.payload.SerialNb_N;
// Pour debug, affichons la valeur BMS
node.warn(`BMS SerialNb: ${BMS} is alive`);
return msg;

// Récupération de l'ID d'esclave
const slaveId = global.get("slaveAddress-Trame1") || 0x01;
const slaveIdNumber = typeof slaveId === 'string' ? parseInt(slaveId, 16) : slaveId;

// ------------------------------------------------------------------
// 1. Vérrou : discovery une seule fois (cohérent avec l'initialisation)
const discoveryKey = `discoverySent_STATIC_BMS_${slaveIdNumber}`;
const discoveryAlreadySent = flow.get(discoveryKey) || false;

// ------------------------------------------------------------------
// 2. Constantes
const baseTopic = "BMS_" + slaveIdNumber;
const discoveryPrefix = "homeassistant";
const deviceName = "BMS_" + slaveIdNumber;
const deviceID = "BMS_" + slaveIdNumber + "_device";

// Champs qui doivent être des "number" (configuration)
const numberFields = [
    "LCD_buzzer_trigger_N", 
    "LCD_buzzer_trigger_value_N", 
    "LCD_buzzer_release_value_N",
    "Request_Charge_voltage_Time_H",
    "Request_Float_voltage_Time_H"
];

// ------------------------------------------------------------------
// 3. Fonctions de génération
function formatValue(v) {
    return (typeof v === 'string') ? v : String(v);
}

function buildDiscoveryMessages(payloadObj) {
    const msgs = [];
    for (const key in payloadObj) {
        const cleanKey = key.replace(/_[A-Z]+$/, "").toLowerCase();
        const sensorTopic = `${baseTopic}/state/${cleanKey}`;

        // Vérifier si c'est un champ "number" (configuration)
        if (numberFields.includes(key)) {
            const commandTopic = `${baseTopic}/control/${cleanKey}/set`;

            // Définir la plage selon le champ
            let min = 0;
            let max = 100;
            let unit = "%";
            let step = 1;
            let icon = "mdi:tune";

            if (key === "LCD_buzzer_trigger_N") {
                max = 25;
                unit = "";
                icon = "mdi:volume-high";
            } else if (key === "Request_Charge_voltage_Time_H" || key === "Request_Float_voltage_Time_H") {
                min = 0;
                max = 25;
                step = 0.1;
                unit = "h";
                icon = "mdi:timer-outline";
            }

            let cfg = {
                name: `BMS ${key.replace(/_[A-Z]+$/, "").replace(/_/g, " ")}`,
                unique_id: `${deviceID}_static_${cleanKey}`,
                state_topic: sensorTopic,
                command_topic: commandTopic,
                min: min,
                max: max,
                step: step,
                mode: "box",
                entity_category: "config",
                enabled_by_default: true,
                icon: icon,
                device: {
                    identifiers: [deviceID],
                    name: deviceName,
                    manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
                    model: payloadObj.BMS_A || "rs485 vers MQTT",
                    sw_version: payloadObj.SW_N || "3.5"
                }
            };

            // Ajouter l'unité seulement si elle existe
            if (unit) {
                cfg.unit_of_measurement = unit;
            }

            msgs.push({
                topic: `${discoveryPrefix}/number/${deviceID}_static/${cleanKey}/config`,
                payload: JSON.stringify(cfg),
                retain: true
            });
        } else {
            // Capteur classique (sensor)
            let cfg = {
                name: `BMS ${key.replace(/_[A-Z]+$/, "").replace(/_/g, " ")}`,
                unique_id: `${deviceID}_static_${cleanKey}`,
                state_topic: sensorTopic,
                enabled_by_default: true,
                // \u274c SUPPRESSION de "entity_category: diagnostic"
                device: {
                    identifiers: [deviceID],
                    name: deviceName,
                    manufacturer: "Smartphoton-JK-BMS / ©JLM 2025",
                    model: payloadObj.BMS_A || "rs485 vers MQTT",
                    sw_version: payloadObj.SW_N || "3.3"
                }
            };

            // unités & classes
            if (key.endsWith("_S")) {
                cfg.unit_of_measurement = "s";
                cfg.device_class = "duration";
                cfg.state_class = "measurement";
            } else if (key.endsWith("_H")) {
                cfg.unit_of_measurement = "h";
                cfg.device_class = "duration";
                cfg.state_class = "measurement";
            } else if (key.endsWith("_N") && key.includes("Time")) {
                cfg.unit_of_measurement = "s";
                cfg.device_class = "duration";
                cfg.state_class = "measurement";
            } else if (key.endsWith("_N") && !key.includes("Serial")) {
                cfg.state_class = "measurement";
            }

            // icônes
            if (key.includes("Password")) cfg.icon = "mdi:form-textbox-password";
            else if (key.includes("Serial")) cfg.icon = "mdi:barcode";
            else if (key.includes("protocol")) cfg.icon = "mdi:protocol";
            else if (key.includes("version") || key.includes("SW") || key.includes("FW"))
                cfg.icon = "mdi:numeric-10";
            else if (key.includes("Uptime")) {
                cfg.icon = "mdi:timer-outline";
                cfg.device_class = "duration";
            } else if (key.includes("date")) cfg.icon = "mdi:calendar";

            msgs.push({
                topic: `${discoveryPrefix}/sensor/${deviceID}_static/${cleanKey}/config`,
                payload: JSON.stringify(cfg),
                retain: true
            });
        }
    }
    return msgs;
}

function buildStateMessages(payloadObj) {
    const msgs = [];
    for (const key in payloadObj) {
        const cleanKey = key.replace(/_[A-Z]+$/, "").toLowerCase();
        msgs.push({
            topic: `${baseTopic}/state/${cleanKey}`,
            payload: formatValue(payloadObj[key]),
            retain: true
        });
    }
    return msgs;
}

// ------------------------------------------------------------------
// 4. Construction des messages
const payload = msg.payload;

var outputMsgs = [];

// Envoyer les messages de discovery seulement si pas déjà fait
if (!discoveryAlreadySent) {
    outputMsgs = buildDiscoveryMessages(payload);
    flow.set(discoveryKey, true);
}

// Ajouter les messages de state
const stateMsgs = buildStateMessages(payload);
