    Number(global.get("slaveAddress-Trame4")) ||
    Number(global.get("slaveAddress-Trame3")) ||
    1;

slaveId = Math.max(1, Math.min(15, slaveId));

const functionCode = 0x03;
const address = 0x12A0;
const registerHigh = (address >> 8) & 0xFF;
const registerLow = address & 0xFF;
const quantityHigh = 0x00;
const quantityLow = 0x02;

function crc16(buffer) {
    let crc = 0xFFFF;
    for (let i = 0; i < buffer.length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            crc = (crc & 1) ? (crc >> 1) ^ 0xA001 : crc >> 1;
        }
    }
    return crc;
}

const dataBuffer = Buffer.from([
    slaveId,
    functionCode,
    registerHigh,
    registerLow,
    quantityHigh,
    quantityLow
]);

const crc = crc16(dataBuffer);
const finalBuffer = Buffer.allocUnsafe(dataBuffer.length + 2);
dataBuffer.copy(finalBuffer);
finalBuffer.writeUInt16LE(crc, dataBuffer.length);

