const views = [];

for (const slot of bmsSlots) {
    views.push(buildLiveView(slot));
    if (!hasMaster) {
        views.push(buildSpecificationsView(slot));
    }
    views.push(buildSetupView(slot));
    views.push(buildDiagnosticView(slot));
    views.push(buildAlarmesView(slot));
}

const dashboard = {
    dashboard_meta: {
        url_path: DASHBOARD_URL_PATH,
        title: DASHBOARD_TITLE,
        icon: DASHBOARD_ICON,
        show_in_sidebar: true,
        require_admin: false
    },
    config: {
        views
    }
};

msg.payload = JSON.stringify(dashboard, null, 2);
msg.filename = DASHBOARD_FILE;

node.status({
    fill: "green",
    shape: "dot",
    text: `dashboard 2: ${hasMaster ? "broadcast master" : "normal"} / ${bmsSlots.length} batteries`
});

return msg;
